import javax.swing.*;
import java.awt.event.*;
public class ClickCounter {
    static int count = 0;

    public static void main(String[] args) {
        JButton btn = new JButton("Click");
        btn.addActionListener(e -> {
            count++;
            System.out.println("clicked: " + count);
        });
        JFrame f = new JFrame();
        f.add(btn);
        f.pack();
        f.setVisible(true);
    }
}
